import React from "react";
import { useParams } from "react-router-dom";
import {
  Container,
  Typography,
  Grid,
  Paper,
  Avatar,
  Divider,
  List,
  ListItem,
  ListItemText,
  Button,
  Box,
} from "@mui/material";

import { doctors } from "../data/doctors"; // fixed import

const DoctorProfile = () => {
  const { doctorId } = useParams(); // ← must be INSIDE the component

  const doctor = doctors.find((d) => d.id === Number(doctorId));

  if (!doctor) {
    return (
      <Container sx={{ py: 8 }}>
        <Typography variant="h5" align="center" color="error">
          Doctor not found
        </Typography>
      </Container>
    );
  }

  return (
    <Container
      maxWidth={false} // ← removes max width limit → full-width page
      sx={{
        py: 8,
        px: { xs: 2, md: 6, lg: 10 }, // lots of side space
        backgroundColor: "#f8f9fa", // light gray background for contrast
      }}
    >
      <Paper
        elevation={0} // no shadow or light shadow
        sx={{
          p: 0,
          backgroundColor: "transparent",
        }}
      >
        <Grid container spacing={4}>
          {/* COLUMN 1 – Big Photo + Name (left) */}
          <Grid item xs={12} md={4}>
            <Paper
              elevation={3}
              sx={{
                p: 5,
                textAlign: "center",
                borderRadius: 3,
                height: "100%",
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                justifyContent: "center",
                backgroundColor: "#ffffff",
              }}
            >
              <Avatar
                src={doctor.image}
                alt={doctor.name}
                sx={{
                  width: { xs: 200, md: 320, lg: 400 }, // very big on large screens
                  height: { xs: 200, md: 320, lg: 400 },
                  mb: 4,
                  border: "8px solid #e3f2fd",
                  boxShadow: 6,
                }}
              />
              <Typography variant="h3" sx={{ fontWeight: "bold", mb: 1 }}>
                {doctor.name}
              </Typography>
              <Typography variant="h5" color="primary" sx={{ mb: 3 }}>
                {doctor.specialty}
              </Typography>
            </Paper>
          </Grid>

          {/* COLUMN 2 – Main Details & Bio (middle – biggest section) */}
          <Grid item xs={12} md={5}>
            <Paper
              elevation={3}
              sx={{
                p: 6,
                borderRadius: 3,
                height: "100%",
                backgroundColor: "#ffffff",
              }}
            >
              <Typography variant="h4" gutterBottom sx={{ mb: 4 }}>
                Professional Details
              </Typography>

              <Divider sx={{ mb: 4 }} />

              <List disablePadding>
                <ListItem sx={{ py: 2.5 }}>
                  <ListItemText
                    primary={<Typography variant="h6">Experience</Typography>}
                    secondary={
                      <Typography variant="body1" sx={{ fontSize: "1.2rem" }}>
                        {doctor.experience}
                      </Typography>
                    }
                  />
                </ListItem>

                <ListItem sx={{ py: 2.5 }}>
                  <ListItemText
                    primary={
                      <Typography variant="h6">Qualification</Typography>
                    }
                    secondary={
                      <Typography variant="body1" sx={{ fontSize: "1.2rem" }}>
                        {doctor.qualification}
                      </Typography>
                    }
                  />
                </ListItem>

                <ListItem sx={{ py: 2.5 }}>
                  <ListItemText
                    primary={<Typography variant="h6">Availability</Typography>}
                    secondary={
                      <Typography variant="body1" sx={{ fontSize: "1.2rem" }}>
                        {doctor.availability}
                      </Typography>
                    }
                  />
                </ListItem>

                <ListItem sx={{ py: 2.5, alignItems: "flex-start" }}>
                  <ListItemText
                    primary={<Typography variant="h6">About</Typography>}
                    secondary={
                      <Typography
                        variant="body1"
                        sx={{ fontSize: "1.2rem", lineHeight: 1.8 }}
                      >
                        {doctor.bio}
                      </Typography>
                    }
                  />
                </ListItem>
              </List>
            </Paper>
          </Grid>

          {/* COLUMN 3 – Book Appointment + extras (right sidebar) */}
          <Grid item xs={12} md={3}>
            <Paper
              elevation={3}
              sx={{
                p: 5,
                borderRadius: 3,
                height: "100%",
                display: "flex",
                flexDirection: "column",
                justifyContent: "center",
                textAlign: "center",
                backgroundColor: "#e3f2fd", // light blue to stand out
              }}
            >
              <Typography variant="h5" gutterBottom sx={{ mb: 4 }}>
                Ready to Book?
              </Typography>

              <Button
                variant="contained"
                color="primary"
                size="large"
                fullWidth
                sx={{
                  py: 3,
                  fontSize: "1.4rem",
                  mb: 4,
                  borderRadius: 3,
                }}
              >
                Book Appointment
              </Button>

              {/* You can add more here later: ratings, location, call button etc. */}
              <Typography variant="body2" color="text.secondary">
                Available today? Call now or schedule online.
              </Typography>
            </Paper>
          </Grid>
        </Grid>
      </Paper>
    </Container>
  );
};

export default DoctorProfile;
